class Solution {
    public int minSwaps(String s) {
        int n = s.length();
        int open = 0, close = 0;
        for (char c : s.toCharArray()) {
            if (c == '[') open++;
            else close++;
        }
        int swaps = Math.abs(open - close);
        return swaps;
    }
}

